mapper.update:

update swm_consolation_money
    set     update_time            = #{updateTime,jdbcType=TIMESTAMP}
       ,update_by              = #{updateBy,jdbcType=BIGINT}


,employee_id            = #{employeeId,jdbcType=BIGINT} 


 ,consolation_money_type = #{consolationMoneyType,jdbcType=VARCHAR}  


 ,application_date       = #{applicationDate,jdbcType=DATE} 


 ,application_money      = #{applicationMoney,jdbcType=DECIMAL} 


 ,relatives_died         = #{relativesDied,jdbcType=VARCHAR} 


 ,oa_order               = #{oaOrder,jdbcType=VARCHAR} 


 , approval_date          = #{approvalDate,jdbcType=DATE} 


 ,status                 = #{status,jdbcType=VARCHAR} 


 ,approval_status        = #{approvalStatus,jdbcType=VARCHAR} 


 ,current_node           = #{currentNode,jdbcType=VARCHAR} 


 ,current_person         = #{currentPerson,jdbcType=VARCHAR} 


 ,export_flag            = #{exportFlag,jdbcType=BIT} 


 ,released_money         = #{releasedMoney,jdbcType=DECIMAL} 


 ,released_flag          = #{releasedFlag,jdbcType=BIT} 


 ,released_time          = #{releasedTime,jdbcType=DATE} 


 ,date                   = #{date, jdbcType = DATE} 


  ,pay_start_date                   = #{payStartDate, jdbcType = DATE} 


  ,pay_end_date                   = #{payEndDate, jdbcType = DATE} 


  ,child_name                   = #{childName, jdbcType = VARCHAR} 


  ,attribute1                   = #{attribute1, jdbcType = VARCHAR} 


  ,attribute2                   = #{attribute2, jdbcType = VARCHAR} 


  ,attribute3                   = #{attribute3, jdbcType = VARCHAR} 


  ,remarks                   = #{remarks, jdbcType = VARCHAR} 


  ,relatives_died_relation                   = #{relativesDiedRelation, jdbcType = VARCHAR} 


  ,spouse_name                   = #{spouseName, jdbcType = VARCHAR} 



 where id = #{id,jdbcType=BIGINT}

mapper.select:

   select case when exists (
            select 1 from swm_consolation_money scm where scm.enabled_flag = 1 and scm.consolation_money_type = '子女诞辰'
            and scm.employee_id = #{employeeId, jdbcType = BIGINT}
            and scm.approval_status != 'notPass'


               and scm.child_name = #{childName,jdbcType = VARCHAR} 


            ) then 1 else 0 end as have_born_flag,


		case when  EXISTS   (
                select 1 from pm_employee_socialrelations pes join pm_employee pe on pe.name = pes.name and
                pe.enabled_flag = 1 and pe.leave_flag = 0 and  pes.enabled_flag = 1 and pes.in_factory_flag = 1 and pes.relationship = '夫妻'
                and pes.employee_id = #{employeeId, jdbcType = BIGINT} and exists (
                select 1 from swm_consolation_money scm_t where scm_t.enabled_flag = 1 and scm_t.employee_id = pe.id
                and scm_t.consolation_money_type = '子女诞辰'
                and scm_t.approval_status != 'notPass'


             and scm_t.child_name = #{childName,jdbcType = VARCHAR} 


                )
            )
				then 1 else 0 end as have_half_born_flag,

        case when exists (
             select 1 from swm_consolation_money scm where scm.enabled_flag = 1 and scm.consolation_money_type = '结婚'
            and scm.employee_id = #{employeeId, jdbcType = BIGINT}
            and scm.approval_status != 'notPass'
        ) then 1 else 0 end as have_married_flag,

        case when exists (
              select 1 from pm_employee_socialrelations pes join pm_employee pe on pe.name = pes.name and
                pe.enabled_flag = 1 and pe.leave_flag = 0 and  pes.enabled_flag = 1 and pes.in_factory_flag = 1 and pes.relationship = '夫妻'
                and pes.employee_id = #{employeeId, jdbcType = BIGINT} and exists (
                select 1 from swm_consolation_money scm_t where scm_t.enabled_flag = 1 and scm_t.employee_id = pe.id
                and scm_t.consolation_money_type = '结婚'
                and scm_t.approval_status != 'notPass'
                )
        ) then 1 else 0 end as have_half_married_flag,


        case when exists  (
                     select 1 from swm_consolation_money scm where scm.enabled_flag = 1 and scm.consolation_money_type = '子女幼托费'
            and scm.employee_id = #{employeeId, jdbcType = BIGINT}


             and scm.child_name = #{childName,jdbcType = VARCHAR} 


            and scm.approval_status != 'notPass'
        ) then 1 else 0 end as have_child_flag,

            case when exists  (
                      select 1 from pm_employee_socialrelations pes join pm_employee pe on pe.name = pes.name and
                pe.enabled_flag = 1 and pe.leave_flag = 0 and  pes.enabled_flag = 1 and pes.in_factory_flag = 1 and pes.relationship = '夫妻'
                and pes.employee_id = #{employeeId, jdbcType = BIGINT} and exists (
                select 1 from swm_consolation_money scm_t where scm_t.enabled_flag = 1 and scm_t.employee_id = pe.id
                and scm_t.consolation_money_type = '子女幼托费'


             and scm_t.child_name = #{childName,jdbcType = VARCHAR} 


                and scm_t.approval_status != 'notPass'
                )
        ) then 1 else 0 end as have_half_child_flag,

            case when #{deadDate, jdbcType = DATE} != null then
             case when exists (
                   select 1 from swm_consolation_money scm where scm.enabled_flag = 1 and scm.consolation_money_type = '丧事' and
                   scm.date = #{deadDate, jdbcType = DATE}
                   and scm.approval_status != 'notPass'
            ) then 1 else 0 end
             else 0 end as have_dead_flag



and scm.enabled_flag = 1
and pe.leave_flag = 0



            and exists (select 1 from swm_consolation_money scm_t where scm_t.id = scm.id and scm_t.id in



                #{item, jdbcType=BIGINT}



        )


    select pej.dept_id, scm.*,pe.name, pe.work_card, (select top 1 fu.email from fnd_user fu where fu.employee_id = pe.id and fu.enabled_flag = 1
) as email
    from swm_consolation_money scm join pm_employee_job pej on
    scm.employee_id = pej.employee_id and pej.enabled_flag = 1 and pej.job_main_flag = 1  and scm.id in    


                    #{item, jdbcType=BIGINT}



            join pm_employee pe on pe.id = scm.employee_id and pe.enabled_flag = 1
